begin;
alter table public.dmq_songs drop constraint if exists dmq_songs_song_number_check;
alter table public.dmq_songs add constraint dmq_songs_song_number_check check (song_number between 1 and 300);
alter table public.dmq_songs add column if not exists question_profile text not null default 'familiar';
alter table public.dmq_songs add column if not exists allowed_questions text[] not null default array['film','title','year','artist']::text[];
alter table public.dmq_songs drop constraint if exists dmq_songs_question_profile_check;
alter table public.dmq_songs add constraint dmq_songs_question_profile_check check (question_profile in ('iconic','familiar','deep','score'));

