insert into public.dmq_songs (song_number,label,title,film,year,artist,spotify_url,enabled,question_profile,allowed_questions)
select * from new_songs
on conflict (song_number) do update set label=excluded.label,title=excluded.title,film=excluded.film,year=excluded.year,artist=excluded.artist,spotify_url=excluded.spotify_url,enabled=excluded.enabled,question_profile=excluded.question_profile,allowed_questions=excluded.allowed_questions,updated_at=now();

update public.dmq_songs set question_profile='iconic' where song_number between 1 and 150 and song_number in (1,2,3,4,5,6,9,10,11,12,15,16,17,20,21,22,25,26,30,31,40,43,47,48,96,97,100,101,102,103,104,107,108,110,113,115,119,122,126,127,130,132,134,135,143,144,147,148,149,150);
update public.dmq_songs set question_profile='deep' where song_number between 1 and 150 and question_profile<>'iconic' and song_number in (38,39,45,46,54,55,59,61,62,65,66,69,71,74,77,81,82,84,85,86,87,88,89,90,91,93,94,95,99,105,106,109,111,112,114,116,117,118,120,121,123,124,125,128,129,131,133,136,137,138,139,140,141,142,145,146);
update public.dmq_songs set question_profile='familiar' where song_number between 1 and 150 and question_profile not in ('iconic','deep');
update public.dmq_songs set question_profile='deep' where song_number in (101,103,109,113,116,129,130,131,132,133,134,135,137,139,140,144,145,146,147,148);
update public.dmq_songs set question_profile='familiar' where song_number in (102,107,108,110,114,115,117,126,127,128,136,143);
update public.dmq_songs set allowed_questions=array['film']::text[] where question_profile='score';
commit;

select count(*) as actieve_songs,count(*) filter (where question_profile='iconic') as iconisch,count(*) filter (where question_profile='familiar') as bekend,count(*) filter (where question_profile='deep') as moeilijk,count(*) filter (where question_profile='score') as instrumentaal from public.dmq_songs where enabled=true;
